arguments.command:
cd /tmp/sv-fbf037c6835d4f2caa845234bebde96f && \
# Use nm to find closest symbols to these addresses
llvm-nm-18 --defined-only libmonosgen-2.0.so.dbg 2>/dev/null | sort | awk '
/^[0-9a-f]/ {
  addr = strtonum("0x" $1)
  name = $3
  if (addr <= 0x2f4b20) { prev1 = name; paddr1 = addr }
  if (addr <= 0x2f4c84) { prev2 = name; paddr2 = addr }
}
END {
  printf "Closest to 0x2f4b20: %s (at 0x%x, offset +0x%x)\n", prev1, paddr1, 0x2f4b20-paddr1
  printf "Closest to 0x2f4c84: %s (at 0x%x, offset +0x%x)\n", prev2, paddr2, 0x2f4c84-paddr2
}'

